{"path": "Dockerfile", "content": "FROM swift:jammy-slim

# Install required system tools
RUN set -eux; \
    apt-get update -qq; \
    apt-get install -y --no-install-recommends git ca-certificates build-essential; \
    rm -rf /var/lib/apt/lists/*

WORKDIR /src
COPY . /src

# Build a Linux placeholder that indicates macOS limitation
RUN set -eux; \
    cat > /src/dorso_placeholder.c << 'EOF'
#include <stdio.h>
int main() {
  printf("Dorso Docker placeholder: This Linux container is a placeholder. Dorso requires macOS AppKit to build/run.\n");
  return 0;
}
EOF

RUN gcc /src/dorso_placeholder.c -o /usr/local/bin/dorso_placeholder && chmod +x /usr/local/bin/dorso_placeholder

ENTRYPOINT ["/usr/local/bin/dorso_placeholder"]
"}
